using System;
using System.Collections.Generic;
using System.Linq;
using System.Net.Http;
using System.Text;
using System.Text.Json;
using System.Threading.Tasks;
using System.Windows;
using System.Windows.Controls;
using System.Windows.Media;
using System.Windows.Threading;

namespace KimiAppNative.IDE.AIModels
{
    /// <summary>
    /// Elegant ChatGPT integration with advanced conversation management and code assistance
    /// </summary>
    public class ChatGPTIntegration : IAIProvider
    {
        private readonly HttpClient _httpClient;
        private readonly List<ChatMessage> _conversationHistory;
        private readonly string _apiKey;
        private string _modelId;
        private int _maxTokens;
        private float _temperature;
        
        // Events for IDE integration
        public event Action<string>? OnResponse;
        public event Action<string>? OnError;
        public event Action<string> OnCodeSuggestion;
        public event Action<string, string> OnCodeGeneration;
        public event Action<string> OnCodeExplanation;
        public event Action<List<CodeIssue>> OnCodeAnalysis;
        public event Action<string> OnConversationResponse;

        public ChatGPTIntegration()
        {
            _httpClient = new HttpClient();
            _conversationHistory = new List<ChatMessage>();
            _apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
            _modelId = "gpt-4-turbo-preview";
            _maxTokens = 4000;
            _temperature = 0.7f;
            
            InitializeSystemPrompts();
        }

        #region Conversation Management

        public async Task<string> SendMessage(string message, bool includeContext = true)
        {
            try
            {
                // Add user message to conversation history
                _conversationHistory.Add(new ChatMessage { Role = "user", Content = message });

                // Prepare context if requested
                var context = includeContext ? await GetCurrentCodeContext() : "";
                var fullMessage = includeContext ? $"{message}\n\nCurrent Code Context:\n{context}" : message;

                // Call ChatGPT API
                var response = await CallChatGPTAPI(fullMessage);
                
                // Add assistant response to conversation history
                _conversationHistory.Add(new ChatMessage { Role = "assistant", Content = response });

                // Trigger event
                OnConversationResponse?.Invoke(response);

                return response;
            }
            catch (Exception ex)
            {
                var errorMsg = $"ChatGPT Error: {ex.Message}";
                OnConversationResponse?.Invoke(errorMsg);
                return errorMsg;
            }
        }

        public void ClearConversation()
        {
            _conversationHistory.Clear();
        }

        public List<ChatMessage> GetConversationHistory()
        {
            return new List<ChatMessage>(_conversationHistory);
        }

        #endregion

        #region Code Assistance Features

        public async Task<string> GenerateCode(string description, string language, string context = "")
        {
            try
            {
                var prompt = CreateCodeGenerationPrompt(description, language, context);
                var response = await CallChatGPTAPI(prompt);
                
                OnCodeGeneration?.Invoke(response, $"Generated {description} in {language}");
                return response;
            }
            catch (Exception ex)
            {
                var errorMessage = $"Code Generation Error: {ex.Message}";
                OnCodeGeneration?.Invoke(errorMessage, "Error");
                return errorMessage;
            }
        }

        public async Task<string> ExplainCode(string code, string language = "")
        {
            try
            {
                var detectedLanguage = string.IsNullOrEmpty(language) ? DetectLanguage(code) : language;
                var prompt = CreateCodeExplanationPrompt(code, detectedLanguage);
                var response = await CallChatGPTAPI(prompt);
                
                OnCodeExplanation?.Invoke(response);
                return response;
            }
            catch (Exception ex)
            {
                var errorMessage = $"Code Explanation Error: {ex.Message}";
                OnCodeExplanation?.Invoke(errorMessage);
                return errorMessage;
            }
        }

        public async Task<List<CodeIssue>> AnalyzeCode(string code, string language = "")
        {
            try
            {
                var detectedLanguage = string.IsNullOrEmpty(language) ? DetectLanguage(code) : language;
                var prompt = CreateCodeAnalysisPrompt(code, detectedLanguage);
                var response = await CallChatGPTAPI(prompt);
                
                var issues = ParseCodeAnalysis(response);
                OnCodeAnalysis?.Invoke(issues);
                return issues;
            }
            catch (Exception ex)
            {
                var errorMessage = $"Code Analysis Error: {ex.Message}";
                OnCodeAnalysis?.Invoke(new List<CodeIssue> { new CodeIssue { Severity = "Error", Description = errorMessage } });
                return new List<CodeIssue>();
            }
        }

        public async Task<string> SuggestCodeCompletion(string code, int cursorPosition, string language = "")
        {
            try
            {
                var detectedLanguage = string.IsNullOrEmpty(language) ? DetectLanguage(code) : language;
                var context = GetCodeContext(code, cursorPosition);
                var prompt = CreateCompletionPrompt(context, detectedLanguage);
                var response = await CallChatGPTAPI(prompt);
                
                OnCodeSuggestion?.Invoke(response);
                return response;
            }
            catch (Exception ex)
            {
                var errorMessage = $"Code Completion Error: {ex.Message}";
                OnCodeSuggestion?.Invoke(errorMessage);
                return errorMessage;
            }
        }

        public async Task<string> RefactorCode(string code, string language = "", string refactoringType = "general")
        {
            try
            {
                var detectedLanguage = string.IsNullOrEmpty(language) ? DetectLanguage(code) : language;
                var prompt = CreateRefactoringPrompt(code, detectedLanguage, refactoringType);
                var response = await CallChatGPTAPI(prompt);
                
                OnCodeGeneration?.Invoke(response, $"Refactored code ({refactoringType})");
                return response;
            }
            catch (Exception ex)
            {
                var errorMessage = $"Code Refactoring Error: {ex.Message}";
                OnCodeGeneration?.Invoke(errorMessage, "Error");
                return errorMessage;
            }
        }

        #endregion

        #region Advanced Features

        public async Task<string> GenerateTests(string code, string language = "", string testFramework = "")
        {
            try
            {
                var detectedLanguage = string.IsNullOrEmpty(language) ? DetectLanguage(code) : language;
                var prompt = CreateTestGenerationPrompt(code, detectedLanguage, testFramework);
                var response = await CallChatGPTAPI(prompt);
                
                OnCodeGeneration?.Invoke(response, "Generated unit tests");
                return response;
            }
            catch (Exception ex)
            {
                var errorMessage = $"Test Generation Error: {ex.Message}";
                OnCodeGeneration?.Invoke(errorMessage, "Error");
                return errorMessage;
            }
